fetch( MyPlugin.ajaxurl, {
    method: 'POST',
    headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
    body: new URLSearchParams({
        action: '${1:action_name}',
        nonce:  MyPlugin.nonce,
        $0
    }),
} )
.then( r => r.json() )
.then( data => {
    if ( ! data.success ) return;
    console.log( data.data );
} );
